/* ==UserStyle==
@name         Youtube Ambient mode for Zen Browser
@version      20260627.13.07
@namespace    ?
@description  Youtube Ambient mode for Zen Browser
@license      No License
==/UserStyle== */

@-moz-document domain("youtube.com") {
 /* =========================================================================

    CONFIGURATION SECTION (ADVANCED SETTINGS)

========================================================================= */
 :root {

     /* --- VISUAL PARAMETERS (POWER AND SIZE) --- */
     --ambi-scale: 4;
     /* Glow range (default: 4) */
     --ambi-blur: 3500px;
     /* Blur radius. (default: 3500px) */
     --ambi-saturate: 400%;
     /* Color saturation (default: 400%) */
     --ambi-brightness: 2.0;
     /* Light intensity (default: 2.0) */
     --ambi-contrast: 1.5;
     /* Contrast (default: 1.5) */
     --ambi-opacity: 0.30;
     /* Total opacity (default: 0.30) */
     /* --- MASK PARAMETERS (VIGNETTE CUTTING OFF BLACK) --- */
     --ambi-mask-start: 35%;
     /* Image fade start point */
     --ambi-mask-end: 75%;
     /* Pixel cut-off point */
     --ambi-fade-time: 0s;
 }

 /* =========================================================================

2. NO CORNER ROUNDING (completely optional)

========================================================================= */
 #ytd-player,

 .html5-video-player,

 .ytp-player-minimized,

 video {

     border-radius: 0px !important;
 }

 /* =========================================================================

3. STRUCTURE AND FILTERS (AMBILIGHT)

========================================================================= */
 html body #cinematics,

 html body #cinematics > div {

     display: flex !important;

     visibility: visible !important;

     background: transparent !important;

     background-color: transparent !important;

     box-shadow: none !important;
 }

 /* Main container - this is where any global softening is applied */
 html body #cinematics > div > div {

     display: flex !important;

     visibility: visible !important;

     background: transparent !important;

     filter: blur(var(--ambi-blur)) saturate(var(--ambi-saturate)) brightness(var(--ambi-brightness)) contrast(var(--ambi-contrast)) !important;

     -webkit-filter: blur(var(--ambi-blur)) saturate(var(--ambi-saturate)) brightness(var(--ambi-brightness)) contrast(var(--ambi-contrast)) !important;

     transform: scale(var(--ambi-scale)) !important;

     opacity: var(--ambi-opacity) !important;

     /* Global delay calculated from the variable */
     transition: filter var(--ambi-fade-time) linear, opacity var(--ambi-fade-time) linear !important;
 }

 /* Canvases generating the image - TOTAL BLOCKING OF TIME INTERFERENCE */
 html body #cinematics canvas {

     display: block !important;

     visibility: visible !important;

     -webkit-mask-image: radial-gradient(ellipse, rgba(0, 0, 0, 1) var(--ambi-mask-start), rgba(0, 0, 0, 0) var(--ambi-mask-end)) !important;

     mask-image: radial-gradient(ellipse, rgba(0, 0, 0, 1) var(--ambi-mask-start), rgba(0, 0, 0, 0) var(--ambi-mask-end)) !important;

     transform: scale(1.4) translateZ(0) !important;

     will-change: opacity, transform;

     /* Aggressive transition blocking eliminates conflict with JavaScript */
     transition: none !important;

     animation: none !important;
 }

 /* =========================================================================

4. INTERFACE BACKGROUND ELIMINATION

========================================================================= */
 .ytp-glow-shadow,

 #player-base,

 ytd-watch-flexy[is-two-columns_] #columns {

     background: transparent !important;

     background-color: transparent !important;

     box-shadow: none !important;
 }
}
